module RefModule (
    input clk,
    input load,
    input shift,
    input [7:0] data_in,
    output reg [7:0] data_out
);

    // Shift register logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (load)
            data_out <= data_in;
        else if (shift)
            data_out <= data_out >> 1;
    end

endmodule
